/**
 * Accessory → Container Mapping
 *
 * Deterministic mapping from Accessory Framework selections to container groups.
 * Each enabled accessory generates one or more container groups with smart defaults.
 *
 * RULES:
 *   - Only enabled accessories generate container groups
 *   - Each group has a sensible default container with name + slot count
 *   - Container allocations are auto-generated when the Accessory Framework is saved
 *   - Removing an accessory removes its container group(s) automatically
 *   - Preserves user-modified slot counts for zones that persist across edits
 *
 * The Accessory Framework is the single source of truth for container generation.
 * No separate container or loadout wizard step is required.
 */


import type { AccessorySelections } from '../components/vehicle-wizard/AccessoryConfigStep';

// ═══════════════════════════════════════════════════════════════
// TYPES
// ═══════════════════════════════════════════════════════════════

export interface ContainerGroup {
  /** Unique group identifier (matches accessory category ID) */
  groupId: string;
  /** Human-readable group label */
  groupLabel: string;
  /** The accessory category ID this group was derived from */
  accessoryCategoryId: string;
  /** Icon name (Ionicons) */
  icon: string;
  /** Accent color */
  color: string;
  /** Sort order for consistent display */
  sortOrder: number;
  /** Default containers auto-generated for this group */
  defaultContainers: ContainerDefault[];
}

export interface ContainerDefault {
  /** Unique container identifier */
  containerId: string;
  /** Default container name */
  name: string;
  /** Default slot count */
  defaultSlots: number;
  /** Zone type classification */
  zoneType: string;
  /** Icon name */
  icon: string;
  /** Accent color */
  color: string;
}

/**
 * A container allocation that the user can modify.
 * Extends ContainerDefault with the user's current slot count.
 */
export interface ContainerAllocation {
  /** Unique container identifier */
  containerId: string;
  /** Container name (user can rename) */
  name: string;
  /** Current slot count (user-adjustable) */
  slotCount: number;
  /** Default slot count (for reset) */
  defaultSlots: number;
  /** Zone type classification */
  zoneType: string;
  /** Icon name */
  icon: string;
  /** Accent color */
  color: string;
  /** Sort order */
  sortOrder: number;
  /** Parent group ID (accessory category) */
  groupId: string;
  /** Parent group label */
  groupLabel: string;
}


