// ═══════════════════════════════════════════════════════════════
// CORE FUNCTIONS
// ═══════════════════════════════════════════════════════════════

/**
 * Get the container groups that should be active based on current accessory selections.
 * Only enabled accessories generate container groups.
 *
 * @param accessories - Current accessory selections from Step 3
 * @returns ContainerGroup[] - Ordered array of active container groups
 */
export function getActiveContainerGroups(
  accessories: AccessorySelections
): ContainerGroup[] {
  const groups: ContainerGroup[] = [];

  for (const [categoryId, state] of Object.entries(accessories)) {
    if (!state?.enabled) continue;

    const mapping = ACCESSORY_CONTAINER_MAP[categoryId];
    if (!mapping) continue;

    groups.push({
      ...mapping,
      accessoryCategoryId: categoryId,
    });
  }

  // Sort by sortOrder for consistent display
  groups.sort((a, b) => a.sortOrder - b.sortOrder);

  return groups;
}

/**
 * Generate container allocations from accessory selections.
 * Each enabled accessory creates its default containers with smart defaults.
 *
 * Preserves user-modified slot counts for containers that still exist
 * from a previous generation (e.g., when going back to Step 3 and returning).
 *
 * @param accessories - Current accessory selections from Step 3
 * @param previousAllocations - Previous allocations to preserve user modifications
 * @returns ContainerAllocation[] - Ordered array of container allocations
 */
export function generateContainerAllocations(
  accessories: AccessorySelections,
  previousAllocations?: ContainerAllocation[],
): ContainerAllocation[] {
  const groups = getActiveContainerGroups(accessories);
  const allocations: ContainerAllocation[] = [];

  // Build lookup of previous slot counts by containerId
  const prevMap = new Map<string, { slotCount: number; name: string }>();
  if (previousAllocations) {
    for (const prev of previousAllocations) {
      prevMap.set(prev.containerId, { slotCount: prev.slotCount, name: prev.name });
    }
  }

  for (const group of groups) {
    for (const container of group.defaultContainers) {
      const prev = prevMap.get(container.containerId);
      allocations.push({
        containerId: container.containerId,
        name: prev?.name || container.name,
        slotCount: prev?.slotCount ?? container.defaultSlots,
        defaultSlots: container.defaultSlots,
        zoneType: container.zoneType,
        icon: container.icon,
        color: container.color,
        sortOrder: group.sortOrder,
        groupId: group.groupId,
        groupLabel: group.groupLabel,
      });
    }
  }

  return allocations;
}

/**
 * Clean orphaned allocations when accessories change.
 * Returns only allocations whose parent accessory is still enabled.
 *
 * @param allocations - Current container allocations
 * @param accessories - Current accessory selections
 * @returns ContainerAllocation[] - Cleaned allocations
 */
export function cleanOrphanedAllocations(
  allocations: ContainerAllocation[],
  accessories: AccessorySelections,
): ContainerAllocation[] {
  const activeGroups = getActiveContainerGroups(accessories);
  const activeGroupIds = new Set(activeGroups.map(g => g.groupId));

  return allocations.filter(a => activeGroupIds.has(a.groupId));
}

/**
 * Get total slot count across all allocations.
 */
export function getTotalSlots(allocations: ContainerAllocation[]): number {
  return allocations.reduce((sum, a) => sum + a.slotCount, 0);
}

/**
 * Get total group count (unique groups).
 */
export function getGroupCount(allocations: ContainerAllocation[]): number {
  const groups = new Set(allocations.map(a => a.groupId));
  return groups.size;
}

/**
 * Convert ContainerAllocations to the ZoneAllocation format used by the existing
 * vehicle config persistence layer. This bridges the new accessory-driven containers
 * with the existing save mechanism.
 */
export function allocationsToZonePayload(
  allocations: ContainerAllocation[],
): {
  zoneName: string;
  zoneType: string;
  slotCount: number;
  color: string;
  icon: string;
  sortOrder: number;
}[] {
  return allocations.map(a => ({
    zoneName: a.name,
    zoneType: a.zoneType,
    slotCount: a.slotCount,
    color: a.color,
    icon: a.icon,
    sortOrder: a.sortOrder,
  }));
}

